# Create an integrated runner that composes the user's existing modules if available,
# otherwise uses safe internal fallbacks. Include live progress and snapshot dumping.
# Then smoke-test briefly and package as a single ZIP for the user to download once.

import os, json, time, hashlib, zipfile, textwrap, importlib.util, sys, types, random, math
from pathlib import Path

root = Path("/mnt/data")
integrated_path = root / "crystal_universe_integrated.py"
readme_path = root / "INTEGRATED_README.txt"
bundle_path = root / "crystal_universe_integrated_bundle.zip"

code = r'''#!/usr/bin/env python3
"""
Crystal Universe — Integrated Brain Runner
------------------------------------------
- Each Spark carries a full SparkMind (dual-process, recursive self-awareness, emotional integration).
- Universe simulates physics + concept vocab + generational drift + operational abstract events.
- Live progress every N ticks and optional JSON snapshots every M ticks.

CLI:
  python crystal_universe_integrated.py run --population 200 --ticks 5000 --snapshots
  python crystal_universe_integrated.py extract --population 200 --ticks 5000 --snapshots
"""

from __future__ import annotations
import os, sys, json, time, random, math, uuid
from dataclasses import dataclass, field
from pathlib import Path
from typing import Dict, List, Tuple, Optional, Any
from collections import Counter

# -------------------------
# Optional imports (user modules). We only use them if present.
# -------------------------
def _try_import(path_name: str, module_name: str):
    p = Path(path_name)
    if not p.exists():
        return None
    spec = None
    try:
        spec = __import__(module_name)  # try by name first if in path
        return spec
    except Exception:
        pass
    # try direct path import
    try:
        import importlib.util
        spec = importlib.util.spec_from_file_location(module_name, str(p))
        mod = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(mod)
        return mod
    except Exception as e:
        return None

MODS = {
    "emotional_depth": _try_import("emotional_depth_mod.py", "emotional_depth_mod"),
    "layer2_dual": _try_import("layer2_unified_dual_process.py", "layer2_unified_dual_process"),
    "layer2_self": _try_import("layer2_recursive_self_awareness.py", "layer2_recursive_self_awareness"),
    "layer2_emote": _try_import("layer2_emotional_integration.py", "layer2_emotional_integration"),
    "layer3_a": _try_import("layer3_cluster_a.py", "layer3_cluster_a"),
    "layer3_b": _try_import("layer3_cluster_b.py", "layer3_cluster_b"),
    "layer3_bind": _try_import("layer3_emotional_binding.py", "layer3_emotional_binding"),
    "layer4_runtime": _try_import("layer4_emotional_crystal_runtime.py", "layer4_emotional_crystal_runtime"),
    "alignment": _try_import("internal_alignment_runtime.py", "internal_alignment_runtime"),
    "voice": _try_import("layer5_autonomous_voice.py", "layer5_autonomous_voice"),
    "harvester": _try_import("subconscious_harvester_web_moral.py", "subconscious_harvester_web_moral"),
    "crystal_engine": _try_import("unified_crystal_engine_with_sensory_wired.py", "unified_crystal_engine_with_sensory_wired"),
}

# -------------------------
# Config
# -------------------------
SPACE_W, SPACE_H = 100.0, 100.0
PHYSICS_LAWS = ['energy','motion','decay','collision','binding','transformation','sync','chaos']
CONCEPT_CATEGORIES = {
    'concrete': ['Apple','Bicycle','Chair','Dog','Elephant','Fork','Guitar','House','Island','Jacket','Kettle','Lighthouse','Mountain','Notebook','Oven','Piano','Quilt','River','Shoe','Television'],
    'natural':  ['Rain','Sun','Tree','Ocean','Bird','MountainPeak','Moon','Fish','Cloud','Flower','Snow','Desert','Volcano','Grass','Animal','Stream','Forest','Stone','Wind','Star'],
    'construct':['Money','Internet','Clock','Law','Book','Car','City','Software','Film','Skyscraper','Airplane','Plastic','Medicine','Fashion','Robot','Highway','Telescope','Currency','Computer','Art'],
    'self':     ['SelfEsteem','SelfWorth','SelfImage','SelfConfidence','SelfAwareness','SelfIdentity','SelfEfficacy','SelfAcceptance','SelfExpression','SelfDoubt','SelfRespect','SelfDiscipline','SelfReliance','SelfPreservation','SelfImprovement','SelfDeception','SelfReflection','SelfCriticism','SelfSufficiency','SelfLove'],
    'abstract': ['Love','Justice','Freedom','Truth','Honor','Bravery','Wisdom','Loyalty','Beauty','Morality','Hope','Faith','Guilt','Joy','Envy','Pride','Grief','Trust','Time','Knowledge'],
}
DEFAULT_ENERGY = 100.0
DEFAULT_DECAY = 0.8
TRANSFER_RATE = 0.05
NEIGHBOR_R = 10.0
REPLICATION_THRESHOLD = 200.0
FUSION_THRESHOLD = 40.0
CLUSTER_R = 12.0
CLUSTER_MIN = 3
AWARENESS_GROWTH = 0.02
KNOWN_THRESHOLD = 0.6
ABSTRACT_EVENT_PROB = 5e-4

# Abstract forces operational effects
ABSTRACT_EFFECTS = {
    "Love": {"trust_boost": 0.08, "binding_cost_mult": 0.7},
    "Justice": {"redistribute": True},
    "Hope": {"energy_inject": (2.0, 7.0)},
    "Grief": {"trust_drop": 0.07, "energy_drain": (1.0, 4.0)},
    "Loyalty": {"cluster_stability": True},
    "Truth": {"decay_reduction": 0.95},
    "Pride": {"overconfidence_risk": True},
}

# -------------------------
# Data Models
# -------------------------
@dataclass
class ConceptVocabulary:
    root_concept: str
    category: str
    law_words: Dict[str, str] = field(default_factory=dict)
    awareness: Dict[str, float] = field(default_factory=dict)
    usage_count: Dict[str, int] = field(default_factory=dict)
    def __post_init__(self):
        for law in PHYSICS_LAWS:
            self.law_words[law] = f"{self.root_concept}-{law}"
            self.awareness[law] = 0.0
            self.usage_count[law] = 0
    def known_words(self):
        return [self.law_words[l] for l in PHYSICS_LAWS if self.awareness.get(l,0.0) >= KNOWN_THRESHOLD]
    def use(self, law: str):
        if law in self.usage_count:
            self.usage_count[law]+=1
            self.awareness[law] = min(1.0, self.awareness[law]+AWARENESS_GROWTH)

# ---- Layer-2 adapters (duck-typed wrappers around user's modules or internal fallbacks) ----
class DualProcessAdapter:
    def __init__(self):
        self.impl = getattr(MODS["layer2_dual"], "DualProcessMind", None) if MODS["layer2_dual"] else None
        self.instance = self.impl() if self.impl else None
    def left(self, stimulus: Dict[str,Any]):
        if self.instance and hasattr(self.instance, "left"):
            return self.instance.left(stimulus)
        energy = stimulus.get("energy",0.0)
        if energy < 60: return {"priority":"survive","confidence":0.9}
        if energy > 160: return {"priority":"replicate","confidence":0.8}
        return {"priority":"explore","confidence":0.6}
    def right(self, neighbors: List[Any]):
        if self.instance and hasattr(self.instance, "right"):
            return self.instance.right(neighbors)
        n = len(neighbors)
        if n == 0: return {"priority":"seek_connection","confidence":0.6}
        if n > 6:  return {"priority":"maintain_cluster","confidence":0.7}
        return {"priority":"explore","confidence":0.6}
    def reconcile(self, left_out: Dict[str,Any], right_out: Dict[str,Any]):
        if self.instance and hasattr(self.instance, "reconcile"):
            return self.instance.reconcile(left_out, right_out)
        if left_out["priority"] == right_out["priority"]:
            return {"action": left_out["priority"], "confidence": (left_out["confidence"]+right_out["confidence"])/2}
        chosen = left_out if left_out["confidence"]>=right_out["confidence"] else right_out
        return {"action": chosen["priority"], "confidence": chosen["confidence"]*0.9}

class RecursiveAwarenessAdapter:
    def __init__(self):
        impl = getattr(MODS["layer2_self"], "RecursiveSelfAwareness", None) if MODS["layer2_self"] else None
        self.instance = impl() if impl else None
        self.journal: List[Dict[str,Any]] = []
    def update_state(self, decision: Dict[str,Any], stimulus: Dict[str,Any]):
        if self.instance and hasattr(self.instance, "update_state"):
            return self.instance.update_state(decision, stimulus)
        entry = {"decision":decision.get("action"), "energy":stimulus.get("energy"), "t":time.time()}
        self.journal.append(entry)
        if len(self.journal)>32: self.journal.pop(0)

class EmotionalIntegrationAdapter:
    def __init__(self):
        impl = getattr(MODS["layer2_emote"], "EmotionalIntegration", None) if MODS["layer2_emote"] else None
        self.instance = impl() if impl else None
        self.state = {"trust":0.5,"calm":0.5,"drive":0.3,"curiosity":0.5}
    def process(self, stimulus: Dict[str,Any], outcome: Optional[str]=None):
        if self.instance and hasattr(self.instance, "process"):
            return self.instance.process(stimulus, outcome)
        # simple adjustment
        e = stimulus.get("energy",0.0)
        self.state["drive"] = min(1.0, max(0.0, 0.3 + (e-100)/200))
        return self.state

@dataclass
class SparkMind:
    dual: DualProcessAdapter = field(default_factory=DualProcessAdapter)
    self_awareness: RecursiveAwarenessAdapter = field(default_factory=RecursiveAwarenessAdapter)
    emotional: EmotionalIntegrationAdapter = field(default_factory=EmotionalIntegrationAdapter)
    vocabulary: Optional[ConceptVocabulary] = None
    decisions: List[str] = field(default_factory=list)
    facets: List[Dict[str,Any]] = field(default_factory=list)
    consciousness: float = 0.0
    def process_tick(self, spark_state: Dict[str,Any], neighbors: List[Any]) -> Dict[str,Any]:
        left = self.dual.left(spark_state)
        right= self.dual.right(neighbors)
        dec = self.dual.reconcile(left,right)
        self.self_awareness.update_state(dec, spark_state)
        self.emotional.process(spark_state)
        self.decisions.append(dec["action"])
        return dec
    def record(self, ftype:str, outcome:str, energy_delta:float, law: Optional[str]=None):
        facet = {"type":ftype,"outcome":outcome,"energy_delta":energy_delta,"emotion":self.emotional.state.copy()}
        if self.vocabulary and law:
            facet["concept_law"]= self.vocabulary.law_words.get(law,"")
            self.vocabulary.use(law)
        self.facets.append(facet)
        if len(self.facets)>12: self.facets.pop(0)
        self.consciousness = min(1.0, self.consciousness + 0.01)

@dataclass
class Spark:
    id: int
    x: float
    y: float
    energy: float = 100.0
    alive: bool = True
    decay: float = 0.8
    generation: int = 0
    mind: SparkMind = field(default_factory=SparkMind)
    def pos(self): return (self.x,self.y)

@dataclass
class Cluster:
    id: int
    members: List[int]
    formed_at: int

class Universe:
    def __init__(self, population:int=200, seed:int=42):
        random.seed(seed)
        self.tick = 0
        self.sparks: Dict[int,Spark] = {}
        self.clusters: Dict[int,Cluster] = {}
        self.events: List[Dict[str,Any]] = []
        for i in range(population):
            x = random.uniform(0,SPACE_W); y = random.uniform(0,SPACE_H)
            s = Spark(id=i, x=x, y=y)
            cat = random.choice([k for k in CONCEPT_CATEGORIES.keys() if k!='abstract'])
            root = random.choice(CONCEPT_CATEGORIES[cat])
            s.mind.vocabulary = ConceptVocabulary(root_concept=root, category=cat)
            self.sparks[i]=s
        self.next_id = population
    def _dist(self,a,b): return math.hypot(a[0]-b[0], a[1]-b[1])
    def neighbors(self, s: Spark, r: float=NEIGHBOR_R):
        out=[]
        for t in self.sparks.values():
            if t.alive and t.id!=s.id and self._dist(s.pos(),t.pos())<=r:
                out.append(t)
        return out
    def step(self):
        self.tick += 1
        # abstract event
        if random.random() < ABSTRACT_EVENT_PROB:
            concept = random.choice(CONCEPT_CATEGORIES['abstract'])
            self._apply_abstract_event(concept)
        for s in list(self.sparks.values()):
            if not s.alive: continue
            nbrs = self.neighbors(s)
            dec = s.mind.process_tick({"energy":s.energy,"pos":s.pos()}, nbrs)
            # Rule: energy transfer
            if nbrs:
                per = s.energy*TRANSFER_RATE
                s.energy = max(0.0, s.energy - per*len(nbrs))
                for n in nbrs: n.energy += per
                s.mind.record("energy_transfer","positive" if per>0 else "neutral",-per*len(nbrs), law="energy")
            # Rule: decay
            s.energy = max(0.0, s.energy - s.decay)
            s.mind.record("decay","negative",-s.decay, law="decay")
            if s.energy<=0: s.alive=False; continue
            # Rule: motion
            nearest = min(nbrs, key=lambda t:self._dist(s.pos(),t.pos()), default=None)
            if nearest:
                dx=nearest.x-s.x; dy=nearest.y-s.y; d=math.hypot(dx,dy)
                if d>0:
                    step = 0.4 if d>NEIGHBOR_R/2 else -0.4
                    s.x = max(0,min(SPACE_W, s.x + step*dx/d))
                    s.y = max(0,min(SPACE_H, s.y + step*dy/d))
            else:
                s.x = max(0,min(SPACE_W, s.x + random.uniform(-0.3,0.3)))
                s.y = max(0,min(SPACE_H, s.y + random.uniform(-0.3,0.3)))
            s.mind.record("motion","neutral",0.0, law="motion")
            # Rule: collision
            collided = [n for n in nbrs if self._dist(s.pos(),n.pos())<1.2]
            if collided:
                cost = 1.5*len(collided)
                s.energy = max(0.0, s.energy - cost)
                s.mind.record("collision","negative",-cost, law="collision")
            # Rule: binding
            if len(nbrs)>=3:
                bind_cost = 0.5
                # Love lowers binding cost if active in last 200 ticks
                if self._recent_force("Love", 200):
                    bind_cost *= ABSTRACT_EFFECTS["Love"]["binding_cost_mult"]
                s.energy = max(0.0, s.energy - bind_cost)
                s.mind.record("binding","positive",-bind_cost, law="binding")
            # Rule: transformation
            if random.random()<0.02:
                # Truth reduces decay
                if self._recent_force("Truth", 200):
                    s.decay = max(0.2, s.decay*ABSTRACT_EFFECTS["Truth"]["decay_reduction"])
                else:
                    s.decay = max(0.2, s.decay*0.98)
                s.mind.record("transformation","positive",0.0, law="transformation")
            # Rule: sync
            if nbrs:
                avg_trust = sum(n.mind.emotional.state.get("trust",0.5) for n in nbrs)/len(nbrs)
                boost = ABSTRACT_EFFECTS["Love"]["trust_boost"] if self._recent_force("Love",200) else 0.0
                s.mind.emotional.state["trust"] = (s.mind.emotional.state["trust"]*0.8) + ((avg_trust+boost)*0.2)
                s.mind.record("sync","positive",0.0, law="sync")
            # Rule: chaos
            if random.random()<0.01:
                delta = random.uniform(-2.0,3.0)
                s.energy = max(0.0, s.energy + delta)
                s.mind.record("chaos","positive" if delta>=0 else "negative", delta, law="chaos")
            # Replication
            if s.energy >= REPLICATION_THRESHOLD:
                self._replicate(s)
            # Fusion
            if s.energy < FUSION_THRESHOLD and nearest and nearest.energy < FUSION_THRESHOLD and nearest.alive:
                self._fuse(s, nearest)
        self._clusters()
    def _recent_force(self, name:str, window:int)->bool:
        return any(ev for ev in self.events if ev.get("type")=="abstract_event" and ev.get("concept")==name and self.tick - ev.get("tick",0) <= window)
    def _apply_abstract_event(self, concept:str):
        ev = {"type":"abstract_event","concept":concept,"tick":self.tick}
        # Apply force
        if concept == "Love":
            # handled via trust boost + cheaper binding for window
            pass
        elif concept == "Justice":
            # redistribute energy across population
            alive = [s for s in self.sparks.values() if s.alive]
            if len(alive)>=2:
                richest = max(alive, key=lambda s:s.energy)
                poorest = min(alive, key=lambda s:s.energy)
                amt = (richest.energy - poorest.energy)*0.25
                richest.energy -= amt
                poorest.energy += amt
        elif concept == "Hope":
            for s in self.sparks.values():
                if s.alive:
                    delta = random.uniform(*ABSTRACT_EFFECTS["Hope"]["energy_inject"]) 
                    s.energy += delta
        elif concept == "Grief":
            for s in self.sparks.values():
                if s.alive:
                    s.energy = max(0.0, s.energy - random.uniform(*ABSTRACT_EFFECTS["Grief"]["energy_drain"]))
                    s.mind.emotional.state["trust"] = max(0.0, s.mind.emotional.state.get("trust",0.5) - ABSTRACT_EFFECTS["Grief"]["trust_drop"])
        elif concept == "Truth":
            # reduce decay globally for a while (handled during transformation)
            pass
        self.events.append(ev)
    def _replicate(self, s: Spark):
        child = Spark(id=self.next_id, x=max(0,min(SPACE_W,s.x+random.uniform(-2,2))), y=max(0,min(SPACE_H,s.y+random.uniform(-2,2))))
        child.energy = s.energy/2; s.energy/=2
        child.generation = s.generation + 1
        # inherit vocab with drift
        child.mind.vocabulary = ConceptVocabulary(root_concept=s.mind.vocabulary.root_concept, category=s.mind.vocabulary.category)
        for law in PHYSICS_LAWS:
            child.mind.vocabulary.awareness[law] = min(1.0, max(0.0, s.mind.vocabulary.awareness[law] + random.uniform(-0.03,0.05)))
            child.mind.vocabulary.usage_count[law] = max(0, s.mind.vocabulary.usage_count[law]//2)
        child.mind.facets = s.mind.facets[-6:].copy()
        self.sparks[child.id]=child; self.next_id+=1
    def _fuse(self, a: Spark, b: Spark):
        if not (a.alive and b.alive): return
        fused = Spark(id=self.next_id, x=(a.x+b.x)/2, y=(a.y+b.y)/2)
        fused.energy = a.energy + b.energy
        # choose vocab with more known words
        a_known = len(a.mind.vocabulary.known_words()); b_known = len(b.mind.vocabulary.known_words())
        chosen = a if a_known>=b_known else b
        fused.mind.vocabulary = ConceptVocabulary(root_concept=chosen.mind.vocabulary.root_concept, category=chosen.mind.vocabulary.category)
        for law in PHYSICS_LAWS:
            fused.mind.vocabulary.awareness[law] = min(1.0, (a.mind.vocabulary.awareness[law]+b.mind.vocabulary.awareness[law])/2)
            fused.mind.vocabulary.usage_count[law] = (a.mind.vocabulary.usage_count[law]+b.mind.vocabulary.usage_count[law])//2
        fused.mind.facets = (a.mind.facets + b.mind.facets)[-12:]
        a.alive=False; b.alive=False
        self.sparks[fused.id]=fused; self.next_id+=1
    def _clusters(self):
        # build semantic clusters: >=2 shared known words + proximity
        alive_ids=[sid for sid,s in self.sparks.items() if s.alive]
        groups=[]; used=set()
        for sid in alive_ids:
            if sid in used: continue
            s=self.sparks[sid]
            known=set(s.mind.vocabulary.known_words())
            group=[sid]; used.add(sid)
            for tid in alive_ids:
                if tid in used or tid==sid: continue
                t=self.sparks[tid]
                if math.hypot(s.x-t.x,s.y-t.y)<=12.0:
                    if len(known & set(t.mind.vocabulary.known_words()))>=2:
                        group.append(tid); used.add(tid)
            if len(group)>=3: groups.append(group)
        self.clusters={}
        for i,g in enumerate(groups):
            self.clusters[i]=Cluster(id=i, members=g, formed_at=self.tick)
    def live_stats(self)->Dict[str,Any]:
        alive=sum(1 for s in self.sparks.values() if s.alive)
        myths=sum(1 for e in self.events if e.get("type")=="abstract_event")
        return {"tick":self.tick,"alive":alive,"clusters":len(self.clusters),"myths":myths}

# --------- Extractor (fallback) ---------
class LanguagePatternExtractor:
    def __init__(self, universe: Universe):
        self.u = universe
    def extract(self)->Dict[str,Any]:
        vocab={}  # category -> root -> stats
        for s in self.u.sparks.values():
            if not s.alive or not s.mind.vocabulary: continue
            cat = s.mind.vocabulary.category; root = s.mind.vocabulary.root_concept
            e = vocab.setdefault(cat, {}).setdefault(root, {"total":0,"words":{}})
            e["total"]+=1
            for law in PHYSICS_LAWS:
                if s.mind.vocabulary.awareness[law]>=0.6:
                    w = s.mind.vocabulary.law_words[law]
                    info = e["words"].setdefault(w, {"law":law,"speakers":0})
                    info["speakers"]+=1
        myths=[ev for ev in self.u.events if ev.get("type")=="abstract_event"]
        return {"concept_vocabularies":vocab,"abstract_myths":myths,"summary":self.u.live_stats()}
    def crystallize(self, out_path:str="crystal_system_memory.json"):
        # Try to use user's crystal engine if available
        if MODS["crystal_engine"] and hasattr(MODS["crystal_engine"], "UnifiedCrystalMemory"):
            mem = MODS["crystal_engine"].UnifiedCrystalMemory()
            data = self.extract()
            # minimal injection
            cid = mem.ensure_concept("concept_vocabularies", "Physics-grounded vocabularies")
            mem.add_text(cid, "definition", json.dumps(data["concept_vocabularies"])[:2000])
            mid = mem.ensure_concept("abstract_archetypes", "Mythic events")
            mem.add_text(mid, "definition", json.dumps(data["abstract_myths"])[:2000])
            mem.save(out_path)
            print(f"✓ Crystallized via UnifiedCrystalMemory -> {out_path}")
            return
        # Fallback JSON write
        with open(out_path,"w",encoding="utf-8") as f:
            json.dump(self.extract(), f, indent=2)
        print(f"✓ Crystallized (fallback JSON) -> {out_path}")

# --------- Snapshots ---------
def write_snapshot(u: Universe, folder: Path, label: str):
    folder.mkdir(parents=True, exist_ok=True)
    data = {
        "summary": u.live_stats(),
        "top_concepts": _top_concepts(u, 10),
        "recent_events": u.events[-10:],
    }
    p = folder / f"sim_state_{label}.json"
    with open(p, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2)

def _top_concepts(u: Universe, k:int):
    cnt=Counter()
    for s in u.sparks.values():
        if s.alive and s.mind.vocabulary:
            cnt[s.mind.vocabulary.root_concept]+=1
    return cnt.most_common(k)

# --------- Runner ---------
def run(population:int=200, ticks:int=5000, progress_every:int=100, snapshots_every:int=500, snapshots:bool=True, seed:int=42, extract_after:bool=True):
    u = Universe(population=population, seed=seed)
    snap_dir = Path("snapshots")
    for t in range(1, ticks+1):
        u.step()
        if t % progress_every == 0:
            s=u.live_stats()
            print(f"[Tick {s['tick']:5d}] Sparks:{s['alive']:4d}  Clusters:{s['clusters']:3d}  Myths:{s['myths']:3d}")
        if snapshots and (t % snapshots_every == 0):
            write_snapshot(u, snap_dir, f"tick_{t}")
    if extract_after:
        ext = LanguagePatternExtractor(u)
        ext.crystallize("crystal_system_memory.json")
    return u

# --------- CLI ---------
def _parse_args(argv):
    import argparse
    p=argparse.ArgumentParser()
    sub=p.add_subparsers(dest="cmd", required=False)
