class HarvesterAdapter:
    def set_intake_mode(self, domain: Optional[str], tier: Tier) -> None:
        if Harvester is None: return
        fn = getattr(Harvester, "set_intake_mode", None)
        if callable(fn):
            fn(domain, str(tier.name).lower()); return
        set_thresh = getattr(Harvester, "set_thresholds", None)
        if callable(set_thresh):
            if tier == Tier.DULL: set_thresh(intake_scale=0.75, pending_scale=1.25)
            elif tier == Tier.PARTIAL: set_thresh(intake_scale=0.5, pending_scale=1.5)
            elif tier == Tier.SUSPEND: set_thresh(intake_scale=0.0, pending_scale=2.0)
    def suspend_domain(self, domain: Optional[str]) -> None:
        fn = getattr(Harvester, "suspend_domain", None)
        if callable(fn): fn(domain)

class UnifiedCrystalAdapter:
    def set_fragment_throttle(self, facet: Optional[str], tier: Tier) -> None:
        if L1 is None: return
        try: setattr(L1, "GLOBAL_FRAGMENT_SCALE",
                     {Tier.DULL:0.75, Tier.PARTIAL:0.5, Tier.SUSPEND:0.0}[tier])
        except: pass
    def freeze_registration(self, facet: Optional[str]) -> None:
        if L1 is None: return
        frozen = getattr(L1, "FROZEN_FACETS", set()); frozen.add(facet or "__all__")
        setattr(L1, "FROZEN_FACETS", frozen)
    def clamp_relation_builders(self, mode: str) -> None:
        if L1 is None: return
        setattr(L1, "RELATION_MODE", mode)

class ClusterBAdapter:
    def set_synthesis_constraints(self, mode: str) -> None:
        if L3B is None: return
        try: setattr(L3B, "SYNTHESIS_MODE", mode)
        except: pass

class EmotionalMetricsAdapter:
    def get_rehab_signals(self) -> Dict[str,float]:
        if L3E is None: return {}
        fn = getattr(L3E, "export_emotional_signals", None)
        return dict(fn() or {}) if callable(fn) else {}
    def l1_stability(self) -> Dict[str,float]:
        if L1 is None: return {}
        out={}; p=getattr(L1,"GLOBAL_EVOLUTION_PRESSURE",None)
        u=getattr(L1,"GLOBAL_USAGE_STABILITY",None)
