# ---------------------------
# Instinct & Rehab
# ---------------------------

class InstinctEngine:
    def gut(self, packet: IntentPacket) -> Dict[str, Any]:
        p, c = packet.foresight_prob, packet.confidence
        level="green"
        if p<0.35 and c>0.6: level="red"
        elif 0.35<=p<0.6 or 0.4<c<0.65: level="yellow"
        return {"level": level, "prob": round(p,3),
                "confidence": round(c,3), "dominant_sense": packet.dominant_sense.value,
                "context": packet.context_hash}
    def flashback(self, packet: IntentPacket) -> Dict[str, Any]:
        return {"type":"flashback","context":packet.context_hash}

class RehabEvaluator:
    def __init__(self, emo: EmotionalMetricsAdapter): self.emo=emo
    def score(self) -> float:
        s=self.emo.get_rehab_signals(); st=self.emo.l1_stability()
        auth, fores, pref = s.get("authenticity",0), s.get("foresight",0), s.get("preference",0)
        evo, usage = st.get("evolution_pressure",0), st.get("usage_stability",0)
        if evo: evo=max(0.0,1.0-min(1.0,float(evo)))
        return max(0.0,min(1.0,0.25*auth+0.25*fores+0.2*pref+0.15*usage+0.15*evo))

# ---------------------------
# Restriction Manager
# ---------------------------

class RestrictionManager:
    def __init__(self, harv, l1, l3b):
        self.harv, self.l1, self.l3b = harv,l1,l3b; self.active={}
    def apply(self, target: Target, tier: Tier, reason: str, ttl_s: float=60.0) -> None:
        rec=RestrictionRecord(target=target,tier=tier,reason=reason,ttl_s=ttl_s)
        self.active[target]=rec; self._enact(rec)
    def _enact(self, rec: RestrictionRecord) -> None:
        t,tier=rec.target,rec.tier
        if t==Target.VISION:
            self.harv.set_intake_mode(None,tier)
            if tier==Tier.SUSPEND: self.harv.suspend_domain(None)
        elif t==Target.LANGUAGE:
            (self.l1.freeze_registration(None) if tier==Tier.SUSPEND
             else self.l1.set_fragment_throttle(None,tier))
        elif t==Target.RELATION:
            self.l1.clamp_relation_builders("off" if tier==Tier.SUSPEND
                                           else "limited" if tier==Tier.PARTIAL else "gentle")
        elif t==Target.CONVERSATION:
            self.l3b.set_synthesis_constraints("suspend" if tier==Tier.SUSPEND
                                               else "cautious" if tier==Tier.PARTIAL else "dull")
    def clear(self,target:Target)->None:
        self.active.pop(target,None)
        if target==Target.VISION: self.harv.set_intake_mode(None,Tier.DULL)
        elif target==Target.LANGUAGE: self.l1.set_fragment_throttle(None,Tier.DULL)
        elif target==Target.RELATION: self.l1.clamp_relation_builders("normal")
        elif target==Target.CONVERSATION: self.l3b.set_synthesis_constraints("normal")

