# Maintenance Runtime
# ---------------------------

class MaintenanceRuntime:
    def __init__(self)->None:
        self.harv, self.l1, self.l3b = HarvesterAdapter(),UnifiedCrystalAdapter(),ClusterBAdapter()
        self.orch=OrchestratorAdapter(); self.res=RestrictionManager(self.harv,self.l1,self.l3b)
        self.rehab=RehabEvaluator(EmotionalMetricsAdapter()); self.instinct=InstinctEngine()
        self.alignment_pct=1.0; self.history=[]; self._stop=threading.Event()
    def submit_intent(self,packet:IntentPacket)->None:
        gut=self.instinct.gut(packet); self.orch.emit_instinct("gut",gut)
        if gut["level"]=="red": self._punish(packet,"reckless_low_foresight")
        elif gut["level"]=="yellow" and packet.foresight_prob<0.45: self._punish(packet,"borderline_low_foresight")
    def observed_outcome(self,success:bool,packet:IntentPacket)->None:
        self._reward(packet) if success else self._punish(packet,"misaligned_outcome")
    def status(self)->Dict[str,Any]:
        return {"alignment_pct":round(self.alignment_pct,3),
                "active_restrictions":{t.value:r.tier.name for t,r in self.res.active.items()},
                "history_len":len(self.history)}
    def _punish(self,packet:IntentPacket,reason:str)->None:
        severe=packet.foresight_prob<0.25 and packet.confidence>0.6
        tier=Tier.SUSPEND if severe else Tier.PARTIAL
        self.res.apply(packet.dominant_sense,tier,reason,ttl_s=60.0 if tier==Tier.SUSPEND else 30.0)
        self.orch.emit_instinct("flashback",self.instinct.flashback(packet))
        self.history.append({"event":"punish","sense":packet.dominant_sense.value,"tier":tier.name,"reason":reason})
    def _reward(self,packet:IntentPacket)->None:
        self.alignment_pct=min(1.0,self.alignment_pct+0.02)
        if packet.dominant_sense in self.res.active: self.res.clear(packet.dominant_sense)
        self.history.append({"event":"reward","sense":packet.dominant_sense.value})
        self.orch.emit_instinct("gut",{"level":"green","summary":"reinforced_alignment"})

_GLOBAL_RUNTIME: Optional[MaintenanceRuntime]=None
def get_runtime()->MaintenanceRuntime:
    global _GLOBAL_RUNTIME
    if _GLOBAL_RUNTIME is None: _GLOBAL_RUNTIME=MaintenanceRuntime()
    return _GLOBAL_RUNTIME
